import{_ as s,y as n,a as o,o as r,a2 as a,D as i}from"./chunks/framework.DCcmcJcL.js";const v=JSON.parse('{"title":"Sales Representatives","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/sales-representative.md","filePath":"b2b-ecommerce-platform/sales-representative.md","lastUpdated":1782311298000}'),p={name:"b2b-ecommerce-platform/sales-representative.md"};function l(m,e,g,c,h,d){const t=n("ImagePopup");return r(),o("div",null,[e[0]||(e[0]=a('<h1 id="sales-representatives" tabindex="-1">Sales Representatives <a class="header-anchor" href="#sales-representatives" aria-label="Permalink to &quot;Sales Representatives&quot;">​</a></h1><p>The Sales Representative feature lets you assign an admin user to manage specific companies. A sales representative becomes the point of contact for their companies — they handle quotation negotiations, receive the related email notifications, and (for non-super-admin users) only see the data for the companies they manage.</p><blockquote><p><strong>Note:</strong> A sales representative is an <strong>admin user</strong>. Any admin user can be assigned as a company&#39;s sales representative.</p></blockquote><h2 id="assigning-a-sales-representative" tabindex="-1">Assigning a Sales Representative <a class="header-anchor" href="#assigning-a-sales-representative" aria-label="Permalink to &quot;Assigning a Sales Representative&quot;">​</a></h2><p>There are two ways to assign a sales representative to a company.</p><h3 id="from-the-company-edit-page" tabindex="-1">From the Company Edit Page <a class="header-anchor" href="#from-the-company-edit-page" aria-label="Permalink to &quot;From the Company Edit Page&quot;">​</a></h3><p><strong>Step: 1</strong> Navigate to <strong>Admin Panel → B2B → Companies</strong> and click <strong>Edit</strong> on a company.</p><p><strong>Step: 2</strong> Open the <strong>Sales Representative &amp; Approval</strong> section.</p><p><strong>Step: 3</strong> Under <strong>Assigned Sales Representative</strong>, select the admin user who should manage this company. Choose <em>No representative assigned</em> to leave it unassigned.</p><p><strong>Step: 4</strong> Click <strong>Update Company</strong> to save.</p>',10)),i(t,{src:"/images/b2b-ecommerce-platform/sales-1.png",alt:"Assign Sales Representative"}),e[1]||(e[1]=a('<h3 id="bulk-assignment-from-the-companies-list" tabindex="-1">Bulk Assignment from the Companies List <a class="header-anchor" href="#bulk-assignment-from-the-companies-list" aria-label="Permalink to &quot;Bulk Assignment from the Companies List&quot;">​</a></h3><p><strong>Step: 1</strong> Navigate to <strong>Admin Panel → B2B → Companies</strong>.</p><p><strong>Step: 2</strong> Select one or more companies using the checkboxes.</p><p><strong>Step: 3</strong> From the mass-action menu, choose <strong>Assign Sales Representative</strong> and pick the admin user.</p><p>All selected companies are updated with the chosen sales representative.</p><h2 id="what-a-sales-representative-can-do" tabindex="-1">What a Sales Representative Can Do <a class="header-anchor" href="#what-a-sales-representative-can-do" aria-label="Permalink to &quot;What a Sales Representative Can Do&quot;">​</a></h2><ul><li><strong>Scoped access –</strong> When a non-super-admin user (one without full permissions) is logged in, they only see the companies, quotations, purchase orders and company catalogs that belong to the companies they manage. Super-admins continue to see everything.</li><li><strong>Quotation negotiation –</strong> The sales representative&#39;s name and email are shown on quotations for the companies they manage, and they handle the buyer–seller negotiation.</li><li><strong>Email notifications –</strong> Seller-side B2B notifications (new quote requests, counter-offers, purchase orders placed, and so on) are sent to the assigned sales representative. If a company has no sales representative, these emails fall back to the store email address.</li></ul><blockquote><p><strong>Note:</strong> A company&#39;s assigned sales representative is also shown in the <strong>Companies</strong> and <strong>Quotations</strong> lists in the admin panel.</p></blockquote>',8))])}const f=s(p,[["render",l]]);export{v as __pageData,f as default};
